advanced.WithAvatar:
// JavaScript
import '@maersk-global/mds-components-core/mc-tag';
import '@maersk-global/mds-components-core/mc-avatar';

// CSS
mc-tag::part(tag) {
  padding-left: 0;
}

// HTML
<mc-tag withaction fit="medium">
  <span slot="icon">
    <mc-avatar fit="x-small" info="info" initials="JD" appearance="color-1"></mc-avatar>
  </span>
  Jane Doe
</mc-tag>

advanced.CustomisedAppearance:
// JavaScript
import '@maersk-global/mds-components-core/mc-tag';

// CSS
mc-tag::part(tag) {
  background-color: transparent;
  border: 1px grey solid;
}
mc-tag::part(text-and-icon-label) {
  font-weight: bold;
}
mc-tag::part(action-button) {
  background-color: #DAF5FF;
  color: #AAEAE0;
  border-color: #DAF5FF;
}

// HTML
<mc-tag label="CSS part" withaction></mc-tag>

advanced.InlineTags:
// JavaScript
import '@maersk-global/mds-components-core/mc-tag';

// CSS
.col {
  display: flex;
  gap: 0.5em;
}

// HTML
<div class="col">
  <mc-tag withaction>Default</mc-tag>
  <mc-tag appearance="info" icon="star" withaction>Info</mc-tag>
  <mc-tag appearance="success" trailingicon="heart">Success</mc-tag>
  <mc-tag appearance="warning" withaction>Warning</mc-tag>
  <mc-tag label="Error" appearance="error" withaction></mc-tag>
</div>

advanced.HandlingAction:
// JavaScript
import '@maersk-global/mds-components-core/mc-tag';
const tag = document.querySelector('mc-tag');
function dismissTag(){
  tag.remove();
}
tag.addEventListener('dismiss', dismissTag)

// HTML
<mc-tag label="remove" withaction></mc-tag>
